void modif(int o,int l,int r,int x,int y,bool oo)

{

	if(l==r){!oo?m0[o]=y:m1[o]=y;return;}

	if(x<=mid) modif(o<<1,l,mid,x,y,oo);

	else modif(o<<1|1,mid+1,r,x,y,oo);

